        [6] = "%s---%s, %s'dan %s adlı, servet yönetiminde mükemmeldir ve gelecekteki nesiller için mirasları korur. Kişiselleştirilmiş yaklaşımı, yüksek net değerli ailelere huzur getirir.",
        [7] = "%s---%s, %s'de %s adlı bir yatırım uzmanı, piyasa karmaşıklıklarını kolaylıkla aşar. Çeşitlendirilmiş portföy uzmanlığı, müşterileri beklenmedik risklerden korur.",
        [8] = "%s---%s, %s'dan %s adlı, yeni nesil için finansal okuryazarlık programlarına öncülük eder. Eğitime olan bağlılığı, daha güvenli bir finansal geleceği garanti eder.",
