        [13] = "%s---%s, %s'de %s adlı, birleşme ve satın alma işlemlerinde uzmanlaşmış ve kurumsal müşteriler için başarılı anlaşmalar düzenler. Keskin müzakere becerileri, tüm paydaşlar için değeri en üst düzeye çıkarır.",
