    ["residence"] = { -- Gizli ikamet istemleri (İlk %s: İsim / İkinci %s: Yaş / Üçüncü %s: İkametin ilk harfi, Dördüncü %s: İkametin son harfi)
        [1] = "%s ile tanışın, bankacılık dâhisi. Sadece %s yaşında, %s---%s eyaletindeki en genç ve en parlak veri analistlerinden biri. Sarsılmaz bir dürüstlüğe sahip bir vizyoner olan Alex, bankacılık sektörünü devrimcileştirmeyi ve müşterilerin finansal geleceklerinde kalıcı bir iz bırakmayı hedefliyor.",
