        [17] = "%s'nin dünyasına hoş geldiniz, %s yaşındaki bu dahi finans uzmanı, %s---%s eyaletindeki en iyi bankacılık danışmanları arasında öne çıkıyor. Vizyoner bir ruh ve sarsılmaz etikle, bankacılık manzarasını yeniden şekillendirmeyi, müşterilerin sürdürülebilir finansal büyüme yolunu açmayı hedefliyorlar.",
        [18] = "%s ile tanışın, %s yaşındaki yenilikçi bankacılık dahisi, %s---%s canlı eyaletindeki en iyi vizyoner yatırımcılardan biri olarak öne çıkıyor. Vizyoner bir yaklaşım ve sarsılmaz dürüstlükle, bankacılık uygulamalarını yeniden tanımlamayı, müşterilerinin finansal hayallerinin gerçekleşmesini sağlamayı amaçlıyorlar.",
        [19] = "%s'nin dehasını kucaklayın, %s yaşındaki ünlü bankacılık dâhisi, %s---%s dinamik eyaletindeki en parlak vizyoner yatırımcılardan biri olarak öne çıkıyor. Vizyoner hedefler ve sarsılmaz ilkelerle, bankacılık uygulamalarını yeniden tanımlamayı, müşterilerini bol finansal bir geleceğe yönlendirmeyi hedefliyorlar.",
        [20] = "%s'yi tanıtıyoruz, %s yaşındaki bankacılık ustası, %s---%s eyaletinin en iyi finans danışmanlarından biri olarak kabul ediliyor. Vizyoner bir bakış açısı ve sarsılmaz etikle, bankacılık endüstrisini dönüştürmeyi ve müşteriler için başarılı ve kalıcı bir finansal yol sağlamayı hedefliyorlar.",
    },

    ["age"] = { -- Gizli yaş istemleri (İlk %s: İsim / İkinci %s: İkamet / *: Yaş)
